// ---------------------------------------------------------------------------
// 2. verifyCrossReferences(dataSources)
// ---------------------------------------------------------------------------
export function verifyCrossReferences(dataSources) {
  // dataSources = {
  //   ISA_UK_STANDARDS, FRS_102_SECTIONS, IFRS_STANDARDS,
  //   COMPANIES_ACT_2006, UK_REGULATORS
  // }
  const results = { valid: 0, missing: 0, errors: [] };

  for (const [ref, mapping] of Object.entries(CROSS_REFERENCE_INDEX)) {
    const sourceData = dataSources[mapping.source];
    if (!sourceData) {
      results.missing++;
      results.errors.push({ ref, error: "Source not found: " + mapping.source });
      continue;
    }
    const found = Array.isArray(sourceData)
      ? sourceData.find(item => item[mapping.matchField] === mapping.matchValue)
      : sourceData[mapping.matchValue];
    if (found) {
      results.valid++;
    } else {
      results.missing++;
      results.errors.push({ ref, error: "No match for " + mapping.matchValue + " in " + mapping.source });
    }
  }

  return results;
}


